        code: '#include <bits/stdc++.h>\nusing namespace std;\n\nclass LRUCache {\n    int cap, time = 0;\n    vector<tuple<int,int,int>> cache; // key, val, lastUsed\npublic:\n    LRUCache(int capacity) : cap(capacity) {}\n    int get(int key) {\n        for (auto& [k,v,t] : cache)\n            if (k == key) { t = time++; return v; }\n        return -1;\n    }\n    void put(int key, int value) {\n        for (auto& [k,v,t] : cache)\n            if (k == key) { v = value; t = time++; return; }\n        if (cache.size() == cap) {\n            auto it = min_element(cache.begin(), cache.end(), [](auto& a, auto& b) { return get<2>(a) < get<2>(b); });\n            cache.erase(it);\n        }\n        cache.push_back({key, value, time++});\n    }\n};',
