        code: '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Node {\n    int key, val;\n    Node* prev; Node* next;\n    Node(int k, int v) : key(k), val(v), prev(nullptr), next(nullptr) {}\n};\n\nclass LRUCache {\n    int cap;\n    unordered_map<int, Node*> mp;\n    Node* head; Node* tail; // dummy nodes\n\n    void remove(Node* node) {\n        node->prev->next = node->next;\n        node->next->prev = node->prev;\n    }\n    void insertFront(Node* node) {\n        node->next = head->next;\n        node->prev = head;\n        head->next->prev = node;\n        head->next = node;\n    }\npublic:\n    LRUCache(int capacity) : cap(capacity) {\n        head = new Node(0,0); tail = new Node(0,0);\n        head->next = tail; tail->prev = head;\n    }\n    int get(int key) {\n        if (!mp.count(key)) return -1;\n        Node* node = mp[key];\n        remove(node);      // detach\n        insertFront(node);  // move to front (most recent)\n        return node->val;\n    }\n    void put(int key, int value) {\n        if (mp.count(key)) {\n            remove(mp[key]);\n            mp[key]->val = value;\n            insertFront(mp[key]);\n            return;\n        }\n        if (mp.size() == cap) { // evict LRU (back)\n            Node* lru = tail->prev;\n            remove(lru);\n            mp.erase(lru->key);\n            delete lru;\n        }\n        Node* node = new Node(key, value);\n        insertFront(node);\n        mp[key] = node;\n    }\n};',
